#!/usr/bin/env bash
# Descarga escudos desde Firebase de Paren La Pelota Futsal (tablas 2026).
set -euo pipefail
DIR="$(cd "$(dirname "$0")/.." && pwd)"
OUT="$DIR/public/escudos/parenlapelota"
mkdir -p "$OUT"

dl() {
  local file="$1"
  local url="$2"
  echo "→ $file"
  curl -fsSL -o "$OUT/$file" "$url"
}

